BIZ_SLUGS.forEach(s=>{parts.push(u('/biz/'+s+'/'));});
 parts.push(u('/biz-cctv/'));
 ['cafe','food','bar','leisure','edu','beauty','medical','retail','service','auto','office','stay','unmanned','mobile'].forEach(c=>{parts.push(u('/biz-cctv/'+c+'/'));});
